        async function exportTarrsToCalTopo(){var gj=window._contourGeojson;if(!gj||!gj.features||gj.features.length===0){setCaltopoExportStatus('error','No contours available to export.');return;}var mapId=document.getElementById('caltopoExportMapId').value.trim();if(!mapId){setCaltopoExportStatus('error','Enter a CalTopo Map ID to export to.');return;}var btn=document.getElementById('exportTarrsBtn');var isIso=gj.features[0]&&gj.features[0].properties.hours!==undefined;var label=isIso?'contours':'TARRs';btn.disabled=true;btn.innerHTML='<span class="spinner"></span> Exporting '+label+'...';setCaltopoExportStatus('info','Pushing '+gj.features.length+' '+label+' to CalTopo...');try{var resp=await fetch('/api/caltopo/export-tarrs',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({map_id:mapId,contours:gj})});var data=await resp.json();if(data.status==='ok'){var okCount=data.results.filter(function(r){return r.status==='ok';}).length;setCaltopoExportStatus('success','Exported '+okCount+'/'+gj.features.length+' '+label+' to CalTopo map '+mapId);}else{setCaltopoExportStatus('error','Export failed: '+(data.message||'Unknown error'));}}catch(err){setCaltopoExportStatus('error','Export failed: '+err.message);}btn.disabled=false;btn.textContent=isIso?'Export Contours to CalTopo':'Export TARRs to CalTopo';}
        async function updateSegmentsOnCalTopo(){var poa=window._poaResults;if(!poa||poa.length===0){setCaltopoExportStatus('error','No POA ranking results available.');return;}var mapId=document.getElementById('caltopoExportMapId').value.trim();if(!mapId){setCaltopoExportStatus('error','Enter a CalTopo Map ID.');return;}var segsToUpdate=[];poa.forEach(function(seg,i){var matchedFeature=null;for(var fi=0;fi<fetchedSegments.length;fi++){if(fetchedSegments[fi].properties.title===seg.title){matchedFeature=fetchedSegments[fi];break;}}if(matchedFeature&&matchedFeature.id){segsToUpdate.push({id:matchedFeature.id,title:seg.title,rank:i+1,poa:seg.poa,cumulative_poa:seg.cumulative_poa});}});if(segsToUpdate.length===0){setCaltopoExportStatus('error','Could not match POA results to CalTopo segment IDs.');return;}var btn=document.getElementById('updateSegsBtn');btn.disabled=true;btn.innerHTML='<span class="spinner"></span> Updating segments...';setCaltopoExportStatus('info','Updating '+segsToUpdate.length+' segment descriptions on CalTopo...');try{var resp=await fetch('/api/caltopo/update-segments',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({map_id:mapId,segments:segsToUpdate})});var data=await resp.json();if(data.status==='ok'){var okCount=data.results.filter(function(r){return r.status==='ok';}).length;setCaltopoExportStatus('success','Updated '+okCount+'/'+segsToUpdate.length+' segment rankings on CalTopo');}else{setCaltopoExportStatus('error','Update failed: '+(data.message||'Unknown error'));}}catch(err){setCaltopoExportStatus('error','Update failed: '+err.message);}btn.disabled=false;btn.textContent='Update Segment Rankings on CalTopo';}
